import { z } from 'zod';

export const E2E241ClientActionSchema = z.object({
  scenarioId: z.literal('e2e-241'),
  fixture: z.enum(['happy_path', 'idempotent_retry', 'downstream_failure', 'permission_denied']),
  action: z.enum(['start_flow', 'retry_same_request', 'simulate_failure', 'recover']),
  idempotencyKey: z.string().uuid(),
}).strict();

export const E2E241TrustedContextSchema = z.object({
  actorId: z.string().min(1),
  tenantId: z.string().min(1),
  role: z.enum(['owner','admin','member','viewer','system']),
  sessionId: z.string().min(1),
}).strict();

export const E2E241ResultSchema = z.object({
  status: z.enum(['passed','failed','denied','retryable_error']),
  httpStatus: z.union([z.literal(200), z.literal(202), z.literal(400), z.literal(403), z.literal(409), z.literal(422), z.literal(500)]),
  code: z.enum(['FLOW_COMPLETED', 'IDEMPOTENT_REPLAY', 'DOWNSTREAM_FAILED', 'PERMISSION_DENIED', 'RECOVERED']),
  userMessage: z.string().min(1),
  assertion: z.object({
    visibleState: z.literal('workflow_state_visible'),
    scenarioTitle: z.literal('Recovery from abandoned signup'),
    redactedTelemetry: z.object({ event: z.literal('e2e.e2e-241.checked'), category: z.literal('saas_onboarding'), redacted: z.literal(true) }),
  }),
}).strict();

backend_solution:
// e2e-241: typed route for Recovery from abandoned signup
export async function handleE2E241(req, ctx) {
  const input = E2E241Schema.parse(await req.json());
  const authz = await ctx.authz.assertCan(input.actorId, 'saas_onboarding', input.tenantId);
  const result = await ctx.db.transaction(tx => ctx.flows.recovery_from_abandoned_signup(tx, input, authz));
  ctx.metrics.observe('error_rate', result.metric);
  return Response.json(ResultSchema.parse(result));
}

frontend_solution:
export function E2E241Probe() {
  const [state, run] = useScenarioProbe('e2e-241', ['happy_path','denied','retry','rollback']);
  return <form aria-label='Recovery from abandoned signup' onSubmit={run}><output role='status'>{state.message}</output><button>Run</button></form>;
}

